 1	import type { FC } from 'react';
 2	
 3	import { Button, ButtonVariant, Popover, Text, TextContent } from '@patternfly/react-core';
 4	import { OutlinedQuestionCircleIcon } from '@patternfly/react-icons';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	const ProjectNameHelp: FC = () => {
 8	  const { t } = useForkliftTranslation();
 9	
10	  return (
11	    <Popover
12	      aria-label={t('Naming information')}
13	      bodyContent={
14	        <TextContent>
15	          <Text component="p">
16	            {t(`A Project name must consist of lower case alphanumeric characters or '-', and must start
17	            and end with an alphanumeric character (e.g. 'my-name' or '123-abc').`)}
18	          </Text>
19	          <Text component="p">
20	            {t(`You must create a Namespace to be able to create projects that begin with 'openshift-',
21	            'kubernetes-', or 'kube-'.`)}
22	          </Text>
23	        </TextContent>
24	      }
25	    >
26	      <Button variant={ButtonVariant.plain} aria-label="View naming information">
27	        <OutlinedQuestionCircleIcon />
28	      </Button>
29	    </Popover>
30	  );
31	};
32	
33	export default ProjectNameHelp;

